{
  "name": "planity-clone",
  "version": "0.1.0",
  "private": true,
  "description": "Planity-like booking marketplace with Apple-style UI",
  "scripts": {
    "dev": "nx run-many --target=serve --projects=@planity/api,@planity/mobile --parallel",
    "prisma:generate": "pnpm --filter @planity/api prisma:generate",
    "build": "nx run-many --target=build --all",
    "test": "nx run-many --target=test --all",
    "lint": "nx run-many --target=lint --all",
    "format": "prettier --write \"**/*.{ts,tsx,js,jsx,json,md}\"",
    "typecheck": "nx run-many --target=typecheck --all",
    "postinstall": "node scripts/patch-android-cmake-path.js"
  },
  "devDependencies": {
    "@nx/eslint": "^18.2.0",
    "@nx/js": "^18.2.0",
    "@nx/node": "^18.2.0",
