    "prettier": "^3.2.5",
    "typescript": "^5.3.3"
  },
  "engines": {
    "node": ">=18.0.0",
    "pnpm": ">=8.0.0"
  },
  "packageManager": "pnpm@8.15.0",
  "pnpm": {
    "packageExtensions": {
      "react-native-safe-area-context": {
        "dependencies": {
          "react-native-builder-bob": "^0.23.0"
